import sys

def solve():
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        N = int(next(it)); x = int(next(it)); k = int(next(it))
        if x % k == 0 or (N + 1 - x) % k == 0:
            out.append('YES')
        else:
            out.append('NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

